import React, { useEffect, useRef, useState } from "react";
import { ChevronDown, Check, X } from "lucide-react";
import { cn } from "@/lib/utils";

interface UpgradefilterDetails {
    filterOptions: {
        group: string;
        key: string;
        options: {
            value: string;
            label: string;
        }[];
    }[];
    filters: Record<string, string[]>;
    onFilterChange: (filter: any) => void;
    defaultLabel?: string;
}

const Upgradefilter = ({
    filterOptions,
    filters,
    onFilterChange,
    defaultLabel = "Filter",
}: UpgradefilterDetails) => {
    const [isOpen, setIsOpen] = useState(false);
    const dropdownRef = useRef<HTMLDivElement>(null);

    const totalSelected = Object.values(filters).flat().length;

    useEffect(() => {
        const handleClickOutside = (e: MouseEvent) => {
            if (dropdownRef.current && !dropdownRef.current?.contains(e.target as Node)) {
                setIsOpen(false);
            }
        };
        document.addEventListener("mousedown", handleClickOutside);
        return () =>
            document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    const toggleValue = (groupKey: string, value: string) => {
        onFilterChange((prev: any) => {
            const exists = prev[groupKey].includes(value);
            return {
                ...prev,
                [groupKey]: exists
                    ? prev[groupKey].filter((v: any) => v !== value)
                    : [...prev[groupKey], value],
            };
        });
    };

    return (
        <div className="relative" ref={dropdownRef}>
            <button
                onClick={() => setIsOpen(!isOpen)}
                className="flex items-center justify-between w-45 px-4 py-1.5 text-sm bg-white  backdrop-blur-sm text-black rounded-lg shadow-sm cursor-pointer outline:none select-none"
            >
                <span>{defaultLabel}</span>
                {totalSelected > 0 && (
                    <span className="ml-2 text-xs bg-blue-600 text-white rounded-full px-2">
                        {totalSelected}
                    </span>
                )}
                <ChevronDown
                    className={cn("w-4 h-4 transition-transform", isOpen && "rotate-180")}
                />
            </button>

            {isOpen && (
                <div className="absolute z-50 mt-2 w-65 bg-white rounded-xl shadow-xl cursor-pointer">
                    {filterOptions.map((group) => (
                        <div key={group.key}>
                            <p className="px-4 py-2 text-xs font-semibold text-black">
                                {group.group}
                            </p>
                            {group.options.map((opt) => {
                                const isSelected = filters[group.key].includes(opt.value);
                                return (
                                    <button
                                        key={opt.value}
                                        onClick={() => toggleValue(group.key, opt.value)}
                                        className={cn(
                                            "flex w-full items-center justify-between px-4 py-2 text-sm",
                                            isSelected
                                                ? "bg-blue-50 text-blue-700"
                                                : "hover:bg-slate-50 text-slate-600"
                                        )}
                                    >
                                        {opt.label}
                                        {isSelected && <Check className="w-4 h-4" />}
                                    </button>
                                );
                            })}
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default Upgradefilter

import { ChevronLeft, ChevronRight } from "lucide-react";
import React from "react";

interface PaginationDetails {
    currentPage: number;
    totalPages: number;
    onPageChange: (page: number) => void;
}

const PaginationControls = ({ currentPage, totalPages = 6, onPageChange }: PaginationDetails) => {
    if (!totalPages || totalPages <= 0) return null;

    return (
        <div className="flex items-center justify-center py-4 gap-1">
            <button
                className="inline-flex items-center gap-1 h-8 px-3 text-[13px] font-medium rounded-md border border-neutral-200 bg-white text-neutral-700 transition-colors hover:bg-neutral-50 disabled:opacity-40 disabled:cursor-not-allowed disabled:hover:bg-white"
                disabled={currentPage === 1 || totalPages <= 1}
                onClick={() => onPageChange(currentPage - 1)}
            >
                <ChevronLeft size={14} />
                Previous
            </button>

            <div className="flex items-center gap-1 mx-2">
                <span className="h-6 min-w-[32px] px-2 inline-flex items-center justify-center text-xs font-medium text-neutral-900 bg-neutral-100 rounded-md border border-neutral-200">
                    {currentPage}
                </span>
                <span className="text-xs text-neutral-400 mx-1">of</span>
                <span className="text-xs font-medium text-neutral-600">
                    {totalPages}
                </span>
            </div>

            <button
                className="inline-flex items-center gap-1 h-8 px-3 text-[13px] font-medium rounded-md border border-neutral-200 bg-white text-neutral-700 transition-colors hover:bg-neutral-50 disabled:opacity-40 disabled:cursor-not-allowed disabled:hover:bg-white"
                disabled={currentPage === totalPages || totalPages <= 1}
                onClick={() => onPageChange(currentPage + 1)}
            >
                Next
                <ChevronRight size={14} />
            </button>
        </div>
    );
};

