}: { items: NavItem[], pathname: string }) {
    return items?.length ? (
        <div className="grid grid-flow-row auto-rows-max text-xs font-medium ml-2">
            {items.map((item, index) => (
                <NavItem key={index} item={item} pathname={pathname} />
            ))}
