function NavItem({ item, pathname, className }: NavItemProps) {
    const isActive = pathname === item.href
    const hasChildren = item.items && item.items.length > 0

    if (hasChildren) {
        return (
            <div>
                <span className={`flex w-full cursor-default items-center rounded-md text-md text-neutral-200 font-medium `}>
                    {item.title}
                </span>
                <div className={`ml-3 border-l border-border pl-3 text-xs ${isActive ? "text-white" : "light:text-[#1e1e1e]"}`}>
                    <DocsSidebarNavItems items={item.items!} pathname={pathname} />
                </div>
            </div>
        )
    }

    if (item.href && !item.disabled) {
        return (
            <Link
                to={item.href}
                className={cn(
                    "group flex w-full items-center rounded-md border border-transparent px-2 py-1",
                    item.disabled && "cursor-not-allowed opacity-60",
                    isActive ? "font-medium dark:text-white text-neutral-900" : "text-zinc-500",
                    className
                )}
                target={item.external ? "_blank" : ""}
                rel={item.external ? "noreferrer" : ""}
            >
                <p className=" hover:underline ">{item.title}</p>
                {item.label === "new" && (
                    <span className="ml-2 rounded-md border border-black bg-[#adfa1d] px-1.5 py-0.5 text-xs leading-none text-[#000000] no-underline group-hover:no-underline">
                        {item.label}
                    </span>
                )}
                {item.label === "recent" && (
                    <span className="ml-2 rounded-md border border-black  px-1.5 py-0.5 text-xs leading-none text-[#000000] no-underline group-hover:no-underline">
                        {item.label}
                    </span>
                )}
                {item.label === "updated" && (
                    <span className="ml-2 rounded-md border border-black bg-pink-400 px-1.5 py-0.5 text-xs leading-none text-[#000000] no-underline group-hover:no-underline">
                        {item.label}
                    </span>
                )}
            </Link>
        )
    }

    return (
        <span
            className={cn(
                "flex w-full cursor-not-allowed items-center rounded-md p-2 text-muted-foreground hover:underline",
                item.disabled && "cursor-not-allowed opacity-60"
            )}
        >
            {item.title}
            {item.label && (
                <span className="ml-2 rounded-md bg-muted px-1.5 py-0.5 text-xs leading-none text-muted-foreground no-underline group-hover:no-underline">
                    {item.label}
                </span>
            )}
        </span>
    )
}

import React from 'react'

interface SkeletonProps {
  variant?: "text" | "rectangular" | "circular",
  width?: string | number,
  height?: string | number,
  className?: string
}

const Skeleton = ({
  variant = "text",
  width = '100%',
  height = '16px',
  className = ''
}: SkeletonProps) => {
  const baseStyles = 'bg-gradient-to-r from-gray-200 via-gray-100 to-gray-200 bg-[length:200%_100%] animate-pulse'

  const variantStyles = {
    text: 'rounded',
    rectangular: 'rounded-md',
    circular: 'rounded-full',
  }

  const selectedVariant = variantStyles[variant] || variantStyles.text

  const circularHeight = variant === 'circular' ? width : height

  return (
    <div
      className={`${baseStyles} ${selectedVariant} ${className}`}
      style={{
        width: typeof width === 'number' ? `${width}px` : width,
        height: typeof circularHeight === 'number' ? `${circularHeight}px` : circularHeight,
      }}
    />
  )
}

export default Skeleton

import { ArrowDown, ArrowUp, ArrowUpFromLine, ChevronDown, ChevronRight, Loader } from "lucide-react";
import React from "react";
import { NavLink } from "react-router-dom";
import { cn } from "@/lib/utils";
import { TableProps } from "@/types/Table";
import Skeleton from "./Skeleton";
export default function Table({
    columns = [],
    data = [],
    isLoading = false,
    actions = [],
    sortConfig = { key: null, direction: null },
    onSort,
    emptyState,
    className,
    expandable = false,
    renderExpandedContent,
    rowKey = (row, index) => row.id || index
}: TableProps) {
    const [expandedRows, setExpandedRows] = React.useState(new Set());

    const toggleRow = (key: any, e: React.MouseEvent) => {
        e.stopPropagation();
        const newExpandedRows = new Set(expandedRows);
        if (newExpandedRows.has(key)) {
            newExpandedRows.delete(key);
        } else {
            newExpandedRows.add(key);
        }
        setExpandedRows(newExpandedRows);
    };

    const handleSort = (key: any) => {
        if (onSort) {
            onSort(key);
        }
    };

    return (
        <div className={cn("w-full overflow-hidden rounded", className)}>
            <div className="w-full overflow-x-auto">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="border-b border-[#e8eaed] bg-[#ffff] shadow-sm">
                            {expandable && (
                                <th className="px-[1.1rem] py-[0.85rem] w-8" />
                            )}
                            {columns.map((col) => (
                                <th
                                    key={col.key}
                                    className={cn(
                                        "px-[1.1rem] py-[0.85rem] text-[11px] font-bold text-[#383838] uppercase tracking-[0.08em] select-none",
                                        col.className
                                    )}
                                    align={col.align || "left"}
                                >
                                    <div
                                        className={cn(
                                            "flex items-center gap-1",
                                            col.sortable && "cursor-pointer hover:text-blue-600 transition-colors",
                                            // col.align === 'right' && "justify-end",
                                            // col.align === 'center' && "justify-center"
                                        )}
                                        onClick={() => col.sortable && handleSort(col.key)}
                                    >
                                        {col.label}
                                        {col.sortable && (
                                            <span className="flex items-center opacity-70">
                                                {sortConfig.key === col.key ? (
                                                    sortConfig.direction === "asc" ? (
                                                        <ArrowUp size={14} className="text-blue-600 ml-1" />
                                                    ) : (
                                                        <ArrowDown size={14} className="text-blue-600 ml-1" />
                                                    )
                                                ) : (
                                                    <div className="w-3.5 h-3.5 ml-1" />
                                                )}
                                            </span>
                                        )}
                                    </div>
                                </th>
                            ))}
                            {actions.length > 0 && (
                                <th className="px-[1.1rem] py-[0.85rem] text-[11px] font-bold text-[#383838] uppercase tracking-[0.08em] text-right w-[1%] whitespace-nowrap">
                                    Actions
                                </th>
                            )}
                        </tr>
                    </thead>

                    <tbody className="border-b border-neutral-600/20  bg-white">
                        {isLoading ? (
                            [...Array(5)].map((_, index) => (
                                <tr key={`skeleton-${index}`} className="animate-pulse">
                                    {columns.map((col, colIndex) => (
                                        <td key={colIndex} className="px-4 py-4">
                                            <Skeleton variant="text" width="80%" height={20} className="bg-white/50" />
                                        </td>
                                    ))}
                                    {actions.length > 0 && (
                                        <td className="px-4 py-4 text-right">
                                            <Skeleton variant="rectangular" width={60} height={24} className="rounded ml-auto bg-white/50" />
                                        </td>
                                    )}
                                </tr>
                            ))
                        ) : data.length > 0 ? (
                            data.map((row, rowIndex) => {
                                const key = rowKey(row, rowIndex);
                                const isExpanded = expandedRows.has(key);
                                return (
                                    <React.Fragment key={key}>
                                        <tr
                                            style={{ animationDelay: `${Math.min(rowIndex * 0.04, 0.4)}s` }}
                                            className={cn(
                                                "border-b border-[#f0f1f4] transition-all duration-200 group animate-[rowIn_0.3s_ease_both]",
                                                isExpanded && "bg-[#f8faff]"
                                            )}
                                        >
                                            {expandable && (
                                                <td className="px-4 py-3 w-8">
                                                    <button
                                                        onClick={(e) => toggleRow(key, e)}
                                                        className="p-1 hover:bg-white/50"
                                                    >
                                                        {isExpanded ? (
                                                            <ChevronDown size={16} className="text-slate-600" />
                                                        ) : (
                                                            <ChevronRight size={16} className="text-slate-600" />
                                                        )}
                                                    </button>
                                                </td>
                                            )}
                                            {columns.map((col) => {
                                                const cellValue = row[col.key];
                                                let displayValue = cellValue;


                                                if (col.key === 'created_at' && cellValue) {
                                                    displayValue = cellValue.length > 10 ? cellValue.slice(0, 4) : cellValue;
                                                }

                                                if (col.render) {
                                                    displayValue = col.render(cellValue, row);
                                                }

                                                if (col.key === 'provider' && cellValue) {
                                                    const val = String(cellValue).toLowerCase();
                                                    if (val.includes('eks') || val.includes('aws')) {
                                                        displayValue = (
                                                            <span className="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-semibold bg-orange-100 text-orange-800 border border-orange-200">
                                                                AWS
                                                            </span>
                                                        );
                                                    } else if (val.includes('azure')) {
                                                        displayValue = (
                                                            <span className="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-semibold bg-blue-100 text-blue-800 border border-blue-200">
                                                                Azure
                                                            </span>
                                                        );
                                                    } else {
                                                        displayValue = (
                                                            <span className="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-semibold bg-slate-100 text-slate-800 border border-slate-200">
                                                                {cellValue}
                                                            </span>
                                                        );
                                                    }
                                                }

                                                if (displayValue === undefined || displayValue === null || displayValue === "") {
                                                    displayValue = "-";
                                                }

                                                return (
                                                    <td
                                                        key={col.key}
                                                        className={cn("px-[1.1rem] py-4 text-[12px] text-[#111827] align-middle", col.cellClassName)}
                                                        align={col.align || "left"}
                                                    >
                                                        {displayValue}
                                                    </td>
                                                );
                                            })}
                                            {actions.length > 0 && (
                                                <td className="px-4 py-2 text-right">
                                                    <div className="flex items-center justify-end gap-1 opacity-80 group-hover:opacity-100 transition-opacity">
                                                        {actions.map((action, actionIndex) => {
                                                            const isDisabled = action.disabled ? action.disabled(row) : false;
                                                            const ActionIcon = action.icon;
                                                            const linkPath = typeof action.link === 'function' ? action.link(row) : action.link;
                                                            const tooltipTitle = typeof action.tooltip === 'function' ? action.tooltip(row) : (action.tooltip || action.label || '');

                                                            const ButtonContent = (
                                                                <div
                                                                    onClick={(e) => {
                                                                        e.stopPropagation();
                                                                        action.onClick?.(row);
                                                                    }}
                                                                    className={cn(
                                                                        "p-1.5 transition-all duration-200 hover:bg-white/60",
                                                                        isDisabled && "opacity-40 cursor-not-allowed",
                                                                        action.color === "error" && !isDisabled && "text-red-500 hover:text-red-700 hover:bg-red-50",
                                                                        action.color === "success" && !isDisabled && "text-green-600 hover:text-green-800 hover:bg-green-50",
                                                                        (!action.color || action.color === "default") && !isDisabled && "text-slate-600 hover:text-blue-600 hover:bg-blue-50"
                                                                    )}
                                                                >
                                                                    {typeof action.icon === 'function' ? (
                                                                        <action.icon row={row} size={16} />
                                                                    ) : action.icon ? (
                                                                        <action.icon size={16} />
                                                                    ) : (
                                                                        <ArrowUpFromLine size={16} />
                                                                    )}
                                                                </div>
                                                            );

                                                            return (
                                                                <div key={actionIndex} title={tooltipTitle} >
                                                                    {linkPath ? (
                                                                        <NavLink to={linkPath} onClick={(e) => e.stopPropagation()}>
                                                                            {ButtonContent}
                                                                        </NavLink>
                                                                    ) : (
                                                                        <span>{ButtonContent}</span>
                                                                    )}
                                                                </div>
                                                            );
                                                        })}
                                                    </div>
                                                </td>
                                            )}
                                        </tr>
                                        {isExpanded && renderExpandedContent && (
                                            <tr>
                                                <td
                                                    colSpan={columns.length + (actions.length > 0 ? 1 : 0) + (expandable ? 1 : 0)}
                                                    className="px-8 py-4 bg-slate-50/50 border-y border-slate-100"
                                                >
                                                    {renderExpandedContent(row)}
                                                </td>
                                            </tr>
                                        )}
                                    </React.Fragment>
                                );
                            })
                        ) : (

                            emptyState && (
                                <tr>
                                    <td
                                        colSpan={columns.length + (actions.length > 0 ? 1 : 0) + (expandable ? 1 : 0)}
                                        className="h-32 text-center text-slate-500"
                                    >
                                        {emptyState}
                                    </td>
                                </tr>
                            )

                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );
}

import React from "react"
import { Moon, Sun } from "lucide-react"
import { motion, AnimatePresence } from "framer-motion"
import { useTheme } from "../theme-provider"
import { cn } from "@workspace/ui/lib/utils"

export const Toggle = () => {
    const { theme, setTheme } = useTheme()

    const toggleTheme = () => {
        setTheme(theme === "dark" ? "light" : "dark")
    }

    return (
        <button
            onClick={toggleTheme}
            className={cn(
                "relative flex items-center justify-center rounded-md transition-all duration-300 py-1.5 px-4 ring-[.5px] ring-black/20",
                "overflow-hidden flex justify-between cursor-pointer relative items-center p-2 dark:ring-[.5px] dark:ring-white/30 hover:ring-white/10 hover:scale-[.98] flex justify-center items-center dark:bg-[var(--bg)] bg-neutral-200 shadow-sm dark:shadow-[var(--shadow-s)] rounded-md outline-0 text-sm gap-2 items-center flex duration-600 ease-inOut ",
                "outline-none focus-visible:ring-primary/50"
            )}
            aria-label="Toggle theme"
        >
            <AnimatePresence mode="wait" initial={false}>
                {theme === "dark" ? (
                    <motion.div
                        key="moon"
                        initial={{ y: 20, opacity: 0, rotate: 45 }}
                        animate={{ y: 0, opacity: 1, rotate: 0 }}
                        exit={{ y: -20, opacity: 0, rotate: -45 }}
                        transition={{ duration: 0.2, ease: "easeInOut" }}
                    >
                        <Moon size={16} className="text-neutral-400 group-hover:text-neutral-200" />
                    </motion.div>
                ) : (
                    <motion.div
                        key="sun"
                        initial={{ y: 20, opacity: 0, rotate: 45 }}
                        animate={{ y: 0, opacity: 1, rotate: 0 }}
                        exit={{ y: -20, opacity: 0, rotate: -45 }}
                        transition={{ duration: 0.2, ease: "easeInOut" }}
                    >
                        <Sun size={16} className="text-yellow-500" />
                    </motion.div>
                )}
            </AnimatePresence>
            <span className="sr-only">Toggle theme</span>
        </button>
    )
}

import { AnimatePresence, motion } from "framer-motion";
import * as React from "react";
import { cn } from "@workspace/ui/lib/utils";
import { LogOut } from "lucide-react";

export interface NotificationMenuItem {
    id: string;
    label: string;
    icon?: React.ReactNode;
    onSelect?: () => void;
}

export interface NotificationWorkspaceItem {
    id: string;
    label: string;
    avatar?: React.ReactNode;
}

export interface NotificationProps {
    avatarSrc: string;
    avatarAlt?: string;
    userLabel: string;
    userSubLabel?: string;
    menuItems: NotificationMenuItem[];
    workspaces?: NotificationWorkspaceItem[];
    onCreateWorkspace?: () => void;
    onLogout?: () => void;
    className?: string;
    open?: boolean;
    onOpenChange?: (open: boolean) => void;
}

export function NotificationMenu(props: NotificationProps) {
    const {
        avatarSrc,
        avatarAlt = "User",
        userLabel,
        userSubLabel,
        menuItems,
        workspaces = [],
        onCreateWorkspace,
        onLogout,
        className,
        open,
        onOpenChange,
    } = props;

    const [uncontrolledOpen, setUncontrolledOpen] = React.useState(false);
    const isControlled = open !== undefined;
    const isOpen = isControlled ? open : uncontrolledOpen;
    const setOpen = (next: boolean) => {
        if (!isControlled) setUncontrolledOpen(next);
        onOpenChange?.(next);
    };

    return (
        <motion.div className={cn("w-full h-fit flex justify-center items-center", className)}>
            <div className="relative w-full">
                <div className="w-full mb-2 flex justify-end px-2 flex-shrink-0 pointer-events-none">
                    <button
                        type="button"
                        onClick={() => setOpen(!isOpen)}
                        className="w-10 h-10 rounded-sm  ring-1 ring-white/20 cursor-pointer duration-600 ease-in-out hover:scale-[.98] pointer-events-auto overflow-hidden"
                        aria-expanded={isOpen}
                        aria-haspopup="menu"
                    >
                        <img
                            src={avatarSrc}
                            alt={avatarAlt}
                            className="w-full h-full object-cover rounded-sm"
                            width={100}
                            height={100}
                        />
                    </button>
                </div>

                <AnimatePresence>
                    {isOpen && (
                        <motion.div
                            key="popup"
                            initial={{ opacity: 0, y: -20, scale: 0.95 }}
                            animate={{ opacity: 1, y: 0, scale: 1 }}
                            exit={{ opacity: 0, y: -10, scale: 0.97 }}
                            transition={{ duration: 0.3, ease: "easeOut" }}
                            className={cn("absolute top-12 right-2 w-[60vw] sm:w-[26vw]  min-h-[56vh] bg-[var(--bg-dark)] ring-[.5px] ring-white/50 rounded-sm overflow-hidden", className)}
                            role="menu"
                        >
                            <div className="upper_col relative">
                                <div
                                    className={cn(
                                        "w-full p-2 flex gap-2 items-center",
                                        "bg-[repeating-linear-gradient(to_right,rgba(255,255,255,0.2)_0.2px,rgba(255,255,255,0.2)_1px,transparent_.5px,transparent_20px),repeating-linear-gradient(to_bottom,rgba(255,255,255,0.2)_0px,rgba(255,255,255,0.2)_1px,transparent_1px,transparent_20px)] [mask-image:linear-gradient(to_bottom_right,black,transparent)]"
                                    )}
                                >
                                    <div className="w-8 h-8 rounded-sm overflow-hidden ring-1 ring-white/20">
                                        <motion.img
                                            initial={{ opacity: 0, scale: 1.1 }}
                                            animate={{ opacity: 1, scale: 1 }}
                                            exit={{ opacity: 0, scale: 1.1 }}
                                            transition={{ duration: 1, ease: "easeInOut" }}
                                            src={avatarSrc}
                                            alt={avatarAlt}
                                            className="rounded-sm object-cover w-full h-full"
                                        />
                                    </div>
                                    <div className="flex flex-col items-start justify-center">
                                        <h1 className="font-medium text-[16px] text-white">{userLabel}</h1>
                                        {userSubLabel ? (
                                            <p className="text-[12px] text-neutral-300">{userSubLabel}</p>
                                        ) : null}
                                    </div>
                                </div>

                                <div className="w-full h-[1px] bg-neutral-800" />

                                {(workspaces.length > 0 || onCreateWorkspace) && (
                                    <div className="p-1 w-full max-h-[20vh] overflow-y-auto">
                                        <div className="p-2 bg-[var(--bg)] backdrop-filter-xs w-full rounded-sm h-full">
                                            <p className="text-[12px] text-neutral-500 mb-2">Switch Workspaces</p>
                                            {workspaces.map((ws) => (
                                                <div key={ws.id} className="mb-2 flex items-center justify-between gap-4">
                                                    <div className="flex items-center justify-start gap-2">
                                                        {ws.avatar ?? (
                                                            <div className="w-4 h-4 bg-purple-400 rounded-sm flex justify-center items-center" />
                                                        )}
                                                        <p className="text-[12px] text-neutral-300">{ws.label}</p>
                                                    </div>
                                                </div>
                                            ))}
                                            {onCreateWorkspace && (
                                                <button
                                                    type="button"
                                                    onClick={onCreateWorkspace}
                                                    className="mb-2 flex items-center justify-start gap-2"
                                                >
                                                    <div className="w-4 h-4 cursor-pointer bg-[var(--bg-light)] rounded-sm flex justify-center items-center">
                                                        +
                                                    </div>
                                                    <p className="text-[12px] cursor-pointer text-neutral-300">Create new</p>
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                )}

                                <div className="w-full h-[1px] bg-neutral-800" />

                                <div className="px-2 py-1 w-full">
                                    {menuItems.map((item) => (
                                        <button
                                            key={item.id}
                                            type="button"
                                            onClick={() => item.onSelect?.()}
                                            className="rounded-sm p-1 w-full text-[14px] hover:bg-[var(--bg)] hover:shadow-[inset_-1px_0px_1px_#ffffff30,0_1px_2px_2px_#00000030,0_2px_2px_#00000015] text-white cursor-pointer flex items-center gap-2"
                                            role="menuitem"
                                        >
                                            {item.icon ? (
                                                <span className="text-gray-400 flex-shrink-0 rounded-full">{item.icon}</span>
                                            ) : null}
                                            <span className="font-medium">{item.label}</span>
                                        </button>
                                    ))}
                                </div>
                                <div className="w-full h-[1px] bg-neutral-800" />
                                <div className="w-full px-2.5 py-1">
                                    {onLogout && (
                                        <button
                                            type="button"
                                            onClick={onLogout}
                                            className={cn(
                                                "w-full flex items-center gap-2",
                                                "rounded-sm px-1 py-1 text-[14px] hover:bg-[var(--bg)] hover:shadow-[inset_-1px_0px_1px_#ffffff30,0_1px_2px_2px_#00000030,0_2px_2px_#00000015] text-white cursor-pointer"
                                            )}
                                        >
                                            <LogOut className="w-3 h-3 text-neutral-400" />
                                            <span>logout</span>
                                        </button>
                                    )}
                                </div>
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>
        </motion.div>
    );
}

export default NotificationMenu;
